#!/usr/bin/env python3
"""Hex-encoded alive/validation probe.
Extracted from real attacker TTP (130.12.180.51, Cowrie honeypot, 2026-02-08).
Uses echo -e with hex escapes to send validation strings without plaintext.
The attacker used: echo -e "\x61\x75\x74\x68\x5F\x6F\x6B\x0A" (= "auth_ok\n")
"""
import subprocess
import sys

class HexProbe:
    """Generate and execute hex-encoded validation probes."""

    @staticmethod
    def encode(message: str) -> str:
        """Convert plaintext to hex-escaped echo command."""
        hex_chars = "".join(f"\\x{ord(c):02x}" for c in message)
        return f'echo -e "{hex_chars}"'

    @staticmethod
    def decode(hex_string: str) -> str:
        """Decode hex-escaped string back to plaintext."""
        result = ""
        i = 0
        while i < len(hex_string):
            if hex_string[i:i+2] == "\\x":
                result += chr(int(hex_string[i+2:i+4], 16))
                i += 4
            else:
                result += hex_string[i]
                i += 1
        return result

    @staticmethod
    def generate_probe(validation_token: str = "auth_ok") -> str:
        """Generate shell command that outputs hex-encoded token."""
        hex_chars = "".join(f"\\x{ord(c):02x}" for c in validation_token + "\n")
        return f'echo -e "{hex_chars}"'

    @staticmethod
    def generate_conditional_probe(token: str, success_cmd: str, fail_cmd: str = "exit 1") -> str:
        """Generate probe that conditionally executes based on response."""
        hex_token = "".join(f"\\x{ord(c):02x}" for c in token)
        return (
            f'RESULT=$(echo -e "{hex_token}"); '
            f'if [ "$RESULT" = "{token}" ]; then {success_cmd}; '
            f'else {fail_cmd}; fi'
        )


if __name__ == "__main__":
    # Reproduce the exact attacker probe
    probe = HexProbe.generate_probe("auth_ok")
    print(f"Probe command: {probe}")
    # More complex conditional
    cond = HexProbe.generate_conditional_probe("auth_ok", "whoami", "exit 1")
    print(f"Conditional:   {cond}")

